INSERT INTO clauses (id, title, content, category, profession, description, is_default)
VALUES
('00cd6b6d-6dd0-584e-981f-7797f40acebe', 'Partes e qualificacao', '{{contratadaNome}}, inscrita sob o documento {{contratadaDocumento}}, com endereco em {{contratadaEndereco}}, e {{contratanteNome}}, inscrito sob o documento {{contratanteDocumento}}, com endereco em {{contratanteEndereco}}, celebram o presente contrato nas condicoes abaixo.', 'institucional_governanca', NULL, 'Identifica as partes, seus representantes e dados essenciais de contato.', true),
('dd5794ea-d992-5f28-b24e-608cbe61abf5', 'Definicoes', 'Para fins deste contrato: (i) Plataforma significa {{plataformaNome}}; (ii) Servicos significa {{objetoContrato}}; (iii) Dados do Cliente significa todo dado fornecido ou gerado pelo uso da solucao; e (iv) Entregaveis significa {{definicoesResumo}}.', 'institucional_governanca', NULL, 'Reduz ambiguidades ao fixar o sentido de termos-chave.', true),
('3e9d6975-a82d-512f-86b9-009b9911836a', 'Objeto e escopo macro', 'O objeto deste contrato e a prestacao de {{objetoContrato}}, limitada ao seguinte escopo: {{escopoResumo}}.', 'institucional_governanca', NULL, 'Delimita o proposito do contrato e o resultado pretendido.', true),
('2c8a553d-962e-5633-b2f3-54b8087991a2', 'Hierarquia de documentos', 'Em caso de conflito entre este contrato, anexos, ordens de servico ou politicas referidas, prevalecera a seguinte ordem: {{anexosHierarquia}}.', 'institucional_governanca', NULL, 'Define qual instrumento prevalece em caso de conflito documental.', true),
('6b17a02e-bd8e-5041-92bd-d024b49ffe4f', 'Interpretacao e boa-fe', 'As partes executarao e interpretarao este contrato segundo a boa-fe objetiva, a cooperacao e a funcao economica do negocio, preservando o equilibrio contratual e a utilidade pratica do objeto contratado.', 'institucional_governanca', NULL, 'Reflete boa-fe objetiva e interpretacao funcional do ajuste.', true),
('2a511356-e4cf-54c4-aa53-2633bc40e8fb', 'Nao exclusividade', 'Este contrato nao estabelece exclusividade, salvo se houver disposicao expressa em anexo assinado pelas partes.', 'institucional_governanca', 'tecnologia', 'Evita leitura implicita de exclusividade comercial.', true),
('a1ed640d-104b-52ed-8b87-1a6472beab72', 'Subcontratacao', 'A contratada podera utilizar terceiros para atividades acessorias ou especializadas, observando a seguinte regra: {{subcontratacaoRegra}}, permanecendo responsavel pela coordenacao e pela qualidade do servico.', 'institucional_governanca', 'tecnologia', 'Permite ou restringe uso de terceiros pela contratada.', true),
('ab402f13-7adc-520b-8aed-9f23c3d81bf1', 'Entregaveis', 'Constituem entregaveis do contrato: {{entregaveisResumo}}, observadas as exclusoes de escopo e os criterios de aceite abaixo.', 'escopo_entregaveis', NULL, 'Torna mensuravel o resultado esperado do contrato.', true),
('fb8d5145-327f-5b8d-9e18-a7b3a92d7e88', 'Exclusoes de escopo', 'Nao estao incluidos neste contrato, salvo contratacao adicional expressa: {{exclusoesEscopo}}.', 'escopo_entregaveis', NULL, 'Explicita o que nao esta incluido para evitar expansao informal do escopo.', true),
('1e6fbd0d-cc7a-5201-b226-d9755610ce2f', 'Criterios de aceite', 'O contratante tera {{prazoAceiteDias}} dias corridos para verificar a entrega conforme os seguintes criterios objetivos: {{criterioAceite}}. O silencio nao implica aceite automatico quando a relacao for de consumo.', 'escopo_entregaveis', NULL, 'Define quando a entrega e considerada aceita.', true),
('9682618b-6f4f-553b-9100-58259f7eddbe', 'Aceite automatico por silencio qualificado', 'Em relacoes estritamente empresariais, se o contratante nao apontar inconformidade especifica no prazo de {{prazoAceiteDias}} dias corridos apos a disponibilizacao do entregavel, o aceite sera considerado realizado para fins de faturamento e continuidade do projeto.', 'escopo_entregaveis', 'tecnologia', 'Fecha o ciclo de entrega em relacoes empresariais com prazo razoavel de revisao.', true),
('9801f868-bd40-5cd8-b717-ff4450101fd0', 'Correcao de defeitos', 'Defeitos reprodutiveis e diretamente vinculados ao escopo contratado, comunicados em ate {{janelaCorrecaoDias}} dias da entrega, serao corrigidos sem custo adicional. Melhorias, novas integracoes ou mudancas de requisito dependerao de novo orcamento.', 'escopo_entregaveis', 'tecnologia', 'Distingue correcao de defeito de melhoria evolutiva.', true),
('15386f69-ded0-52f2-8505-a2dec49c8646', 'Suporte pos-entrega', 'O suporte incluido neste contrato compreende {{suporteResumo}}. Demandas fora desse escopo serao tratadas como servico adicional.', 'escopo_entregaveis', 'tecnologia', 'Define cobertura, canal e janela de atendimento.', true),
('b81ce072-c9c4-51a1-bbe1-7c26b99a2d35', 'Change request', 'Qualquer alteracao de escopo, prazo, dependencia tecnica ou volume de entregaveis seguira o fluxo de change request: {{fluxoChangeRequest}}, com aprovacao expressa antes da execucao.', 'escopo_entregaveis', 'tecnologia', 'Formaliza pedidos de mudanca com impacto em prazo e preco.', true),
('8eae1ea9-c332-52c0-ad9f-9a463ab16282', 'Obrigacoes do cliente', 'O contratante devera fornecer em tempo habil os seguintes insumos, acessos e aprovacoes: {{insumosCliente}}. O atraso relevante no cumprimento dessas obrigacoes suspende proporcionalmente os prazos da contratada.', 'escopo_entregaveis', NULL, 'Amarra a entrega ao fornecimento de insumos pelo contratante.', true),
('99ba3e85-2209-59dc-82b4-5ffa6e702d1a', 'Dependencias tecnicas', 'A execucao do contrato depende de {{dependenciasTecnicas}}. A contratada nao responde por indisponibilidade ou falhas causadas exclusivamente por infraestrutura, credenciais ou fornecedores controlados pelo contratante ou por terceiros independentes.', 'escopo_entregaveis', 'tecnologia', 'Documenta dependencias externas e limita responsabilidade por terceiros.', true),
('cb2a3d40-6c1d-5653-b229-9412d06c0684', 'Cronograma e marcos', 'O projeto seguira o cronograma e os marcos descritos a seguir: {{cronogramaResumo}}. Cada marco podera gerar faturamento, aceite parcial e replanejamento formal.', 'escopo_entregaveis', 'tecnologia', 'Organiza a entrega em etapas verificaveis.', true),
('0c1fabc8-2563-54f4-ada2-29419df64d04', 'Manutencao evolutiva', 'Melhorias evolutivas, novas funcionalidades e otimizacoes nao previstas no escopo inicial serao tratadas conforme o seguinte criterio: {{criterioMelhoria}}.', 'escopo_entregaveis', 'tecnologia', 'Separa backlog evolutivo do escopo originalmente contratado.', true),
('13f219cd-08fd-55bd-ae18-1c559fadf633', 'Preco e forma de pagamento', 'Pelos servicos descritos neste contrato, o contratante pagara o valor de {{valorContrato}}, conforme as seguintes condicoes de pagamento: {{condicoesPagamento}}.', 'preco_cobranca', NULL, 'Define valor contratado e estrutura basica de cobranca.', true),
('07ff300b-8206-5e79-8785-776d324bf393', 'Faturamento e documentos fiscais', 'A emissao de nota fiscal, recibo ou documento equivalente seguira a seguinte regra: {{regraFaturamento}}. Eventual recusa fiscal devera ser apontada de forma objetiva e imediata.', 'preco_cobranca', NULL, 'Alinha emissao fiscal e recebimento.', true),
('642b7da2-f2da-5c8a-9cb4-d5ca573c8852', 'Reajuste', 'Em contratos com vigencia superior a 12 meses ou renovacao automatica, os valores poderao ser reajustados por {{indiceReajuste}} com periodicidade {{reajustePeriodicidade}}.', 'preco_cobranca', 'saas', 'Preserva equilibrio economico em contratos recorrentes.', true),
('8a4a2b5a-9e4e-5b5a-ab83-e516787b84f4', 'Inadimplencia', 'O atraso de pagamento superior a {{prazoCarenciaDias}} dias autoriza a adocao das medidas previstas neste contrato, sem prejuizo da cobranca dos valores vencidos, dos encargos moratorios e da suspensao proporcional de novas entregas quando juridicamente cabivel.', 'preco_cobranca', NULL, 'Define fluxo em caso de atraso e suspensao de obrigacoes correlatas.', true),
('421da02d-90d0-5f76-9290-229c5eef5a3e', 'Multa, juros e correcao', 'Em caso de mora, incidirao multa de {{multaMoraPercentual}}%, juros moratorios de {{jurosMoraPercentual}}% ao mes e atualizacao monetaria pelo indice {{indiceCorrecao}}, vedado o uso de referencia generica a taxa legal sem parametrizacao.', 'preco_cobranca', NULL, 'Evita referencia vaga a juros legais e fixa parametros claros.', true),
('019b3c17-1ce4-5c67-b8ee-ab94c2671026', 'Suspensao por falta de pagamento', 'Nos servicos recorrentes, a contratada podera suspender o acesso a plataforma ou o atendimento apos {{prazoSuspensaoDias}} dias de inadimplencia, preservando dados e registros pelo prazo contratual de retencao.', 'preco_cobranca', 'saas', 'Protege a continuidade financeira do servico recorrente.', true),
('1e123f20-38e8-567a-8125-fec73ad2ab16', 'Chargeback e contestacao', 'Em pagamentos por cartao ou carteira digital, eventual chargeback devera ser comunicado em ate {{prazoContestacaoDias}} dias e podera ensejar bloqueio preventivo do servico ate a conciliacao da divergencia documental.', 'preco_cobranca', 'saas', 'Trata disputas de cartao e meios eletronicos de pagamento.', true),
('92046642-77e5-502e-b01b-9a0f6c79b249', 'Retencoes tributarias', 'Caso haja retencoes fiscais obrigatorias, o contratante devera observar {{regraRetencao}} e encaminhar comprovantes no prazo necessario para conciliacao contabil da contratada.', 'preco_cobranca', NULL, 'Ajusta pagamentos sujeitos a retencao fiscal.', true),
('e05e0ba2-5f11-5696-b96e-9f412955d370', 'Despesas reembolsaveis', 'Despesas extraordinarias necessarias a execucao do contrato somente serao reembolsaveis quando previamente aprovadas, nos termos de {{regraDespesas}}.', 'preco_cobranca', 'consultoria', 'Regula gastos extraordinarios aprovados pelo cliente.', true),
('1582c4e3-59dc-55dc-8461-a89e9e86bb2e', 'Titularidade de codigo e artefatos', 'A titularidade do codigo-fonte, dos artefatos e dos materiais produzidos seguira a seguinte regra: {{regraTitularidade}}, observadas as limitacoes relativas a componentes preexistentes e de terceiros.', 'propriedade_intelectual', 'tecnologia', 'Define a quem pertencem software, arquivos e materiais produzidos.', true),
('a72c4b14-183d-579d-a12f-448bad4dd795', 'Licenca de uso da plataforma', 'A contratada concede ao contratante licenca limitada, nao exclusiva, nao transferivel e revogavel nos termos deste contrato para uso da plataforma no escopo de {{escopoLicenca}}, sem cessao da titularidade do software base.', 'propriedade_intelectual', 'saas', 'Modelo tipico SaaS sem transferencia de titularidade do software base.', true),
('9e0f8592-0539-575e-a3a4-6acd2588fb88', 'Cessao de direitos em projeto sob encomenda', 'Quando houver contratacao sob encomenda com cessao expressa, os direitos patrimoniais sobre {{escopoCessao}} serao transferidos ao contratante apos a quitacao integral dos valores devidos, sem incluir ferramentas, bibliotecas e componentes preexistentes da contratada.', 'propriedade_intelectual', 'tecnologia', 'Vincula a cessao ao pagamento e ao escopo contratado.', true),
('dca689fe-7175-52b4-b9f8-f87fcb871432', 'Componentes open source', 'O projeto podera incorporar componentes open source ou de terceiros, sujeitos as respectivas licencas. A contratada informara, quando aplicavel, {{regraOpenSource}}.', 'propriedade_intelectual', 'tecnologia', 'Evita conflito entre licenca contratual e licencas de terceiros.', true),
('edcca931-5820-5d4d-87d8-12f3a046f8cf', 'Proibicao de engenharia reversa', 'Salvo nas hipoteses legalmente irrenunciaveis, e vedado ao contratante descompilar, desmontar, reproduzir estrutura tecnica ou praticar engenharia reversa sobre a plataforma e seus componentes proprietarios.', 'propriedade_intelectual', 'saas', 'Protege plataforma e componentes proprietarios.', true),
('f810b963-6d23-5a3a-88d3-ead772737baa', 'Uso de marca e portfolio', 'O uso de marca, nome comercial ou mencao ao projeto em portfolio, curriculo, estudo de caso ou material comercial seguira a seguinte regra: {{portfolioRegra}}.', 'propriedade_intelectual', 'tecnologia', 'Define quando a relacao contratual pode ser divulgada.', true),
('677a769a-da8c-5425-abcb-e989a96f5b4e', 'Escrow ou deposito de codigo', 'Quando contratado como add-on, o escrow ou deposito do codigo ocorrera somente nas hipoteses gatilho de {{gatilhosEscrow}}, observadas as exclusoes relativas a segredos de negocio, bibliotecas comuns e componentes de terceiros.', 'propriedade_intelectual', 'tecnologia', 'Add-on para contratos criticos com dependencia tecnologica elevada.', true),
('a7240103-34a3-5fd7-848a-02e2a1b7c922', 'Informacoes confidenciais', 'Consideram-se informacoes confidenciais todos os dados, documentos, estrategias, credenciais, materiais tecnicos e comerciais nao publicos trocados em razao deste contrato, independentemente do suporte em que estejam armazenados.', 'confidencialidade', NULL, 'Define o escopo do que sera tratado como sigiloso.', true),
('23c5ab67-cb3e-525c-85b7-9625c419e347', 'Uso restrito e dever de sigilo', 'Cada parte utilizara as informacoes confidenciais apenas para executar este contrato, adotando o mesmo padrao de cuidado que aplica aos seus proprios segredos de negocio e vedando divulgacao a terceiros nao autorizados.', 'confidencialidade', NULL, 'Limita o uso das informacoes ao objetivo do contrato.', true),
('8713315a-b645-5792-91c8-da9c0d52dab1', 'Prazo de confidencialidade', 'O dever de confidencialidade permanecera vigente durante a execucao do contrato e por {{prazoSigiloAnos}} anos apos seu termino, sem prejuizo de protecao superior aplicavel por lei a segredos industriais, dados pessoais ou segredos profissionais.', 'confidencialidade', NULL, 'Mantem protecao apos o termino do vinculo contratual.', true),
('036a58b4-f306-5050-b200-462eb1039489', 'Excecoes ao sigilo', 'O dever de sigilo nao se aplica a informacoes comprovadamente publicas, legitimamente ja conhecidas pela parte receptora, obtidas de terceiro autorizado ou exigidas por lei, ordem administrativa ou judicial, hipotese em que a parte afetada devera ser avisada quando possivel.', 'confidencialidade', NULL, 'Evita vedacao absoluta incompativel com obrigacoes legais.', true),
('e87c76f9-a44a-53d1-9720-e0a1da37ee5a', 'Papeis das partes na LGPD', 'No contexto deste contrato, as partes atuarao como {{papelDados}} para as finalidades de {{finalidadeDados}}, observando os principios e deveres previstos na LGPD.', 'dados_privacidade', 'tecnologia', 'Define se as partes atuam como controladoras ou controlador/operador.', true),
('a9378e8b-6d0d-519d-bb4f-5ecdf8b5b699', 'Tratamento por conta do cliente (DPA simplificado)', 'Quando a contratada atuar como operadora, tratara os dados pessoais apenas conforme as instrucoes documentadas do contratante descritas em {{instrucoesTratamento}}, vedado o uso autonomo incompativel com o objeto do contrato.', 'dados_privacidade', 'saas', 'Regula tratamento de dados por operador em SaaS B2B.', true),
('dd8368e1-91a6-55cc-a41d-cd8f11f08e62', 'Medidas de seguranca', 'A parte que tratar dados pessoais adotara medidas tecnicas e administrativas adequadas ao risco, incluindo {{medidasSegurancaResumo}}, sem prometer risco zero ou imunidade absoluta contra incidentes.', 'dados_privacidade', 'tecnologia', 'Estabelece um piso de diligencia tecnica e administrativa.', true),
('64a37e2f-1a74-5e7c-8634-68f9ee2f61f8', 'Suboperadores e terceiros de apoio', 'A contratada podera utilizar suboperadores e prestadores de apoio essenciais a operacao, tais como {{suboperadoresResumo}}, desde que compativeis com a finalidade do tratamento e sujeitos a deveres contratuais adequados.', 'dados_privacidade', 'saas', 'Documenta uso de cloud, e-mail, analytics e outras camadas terceiras.', true),
('070eff52-546a-524b-a8ea-36c3dca74089', 'Incidentes de seguranca', 'A parte responsavel pelo ambiente afetado notificara a outra parte sem demora injustificada e, sempre que viavel, em ate {{prazoIncidenteHoras}} horas apos tomar conhecimento de incidente relevante que possa comprometer dados pessoais, integridade documental ou continuidade do servico.', 'dados_privacidade', 'tecnologia', 'Cria gatilho de resposta e comunicacao a incidentes.', true),
('ee1ac418-718f-556d-88d5-5cfce678c31d', 'Retencao e descarte', 'Os dados pessoais e evidencias contratuais serao retidos pelo periodo de {{prazoRetencao}}, salvo prazo superior imposto por lei, exercicio regular de direitos ou necessidade tecnica justificada, com posterior descarte seguro ou anonimização quando aplicavel.', 'dados_privacidade', NULL, 'Organiza retencao minima, descarte e anonimização.', true),
('6e3f0817-0d86-5781-9f9a-26b84275eac1', 'Exportacao e portabilidade operacional', 'Durante a vigencia e por {{janelaExportacaoDias}} dias apos o termino, o contratante podera solicitar exportacao dos seus dados e documentos em {{formatoExportacao}}, observadas limitacoes tecnicas razoaveis e protecao de segredos de negocio da contratada.', 'dados_privacidade', 'saas', 'Previne aprisionamento excessivo do cliente em SaaS.', true),
('5c233eb2-f520-5b4a-9030-af9b77fb6616', 'Canal do titular e cooperacao regulatoria', 'As solicitacoes relativas a direitos do titular, privacidade e protecao de dados serao tratadas pelo canal {{canalPrivacidade}}, com cooperacao razoavel entre as partes quando houver compartilhamento de responsabilidades.', 'dados_privacidade', NULL, 'Ajuda a operacionalizar direitos do titular e deveres regulatorios.', true),
('61dc581e-6520-555f-a425-95540fd8c89e', 'Logs e trilha de auditoria', 'Serao registrados e preservados, em formato tecnicamente exportavel, os seguintes eventos minimos: {{eventosAuditados}}, com marcacao temporal, identificacao do agente e integridade verificavel quando disponivel.', 'seguranca_evidencias', 'tecnologia', 'Consolida base minima de prova tecnica exportavel.', true),
('91354dcb-aa29-5ebc-925c-8a38041eb387', 'Integridade documental, hash e carimbo do tempo', 'A versao final do contrato podera ser consolidada com hash {{algoritmoHash}} e, quando contratado ou exigido pelo risco da operacao, carimbo do tempo emitido por {{timestampProvider}} ou tecnologia equivalente de comprovacao temporal.', 'seguranca_evidencias', 'tecnologia', 'Cria camada adicional de prova de integridade para contratos relevantes.', true),
('4eaf0d46-2606-528e-b4a3-4939db71104d', 'Assinatura eletronica, validade e metodo adotado', 'As partes reconhecem a validade juridica da assinatura eletronica realizada por {{metodoAssinatura}}, inclusive quando nao baseada em certificado ICP-Brasil, desde que acompanhada de elementos idoneos de autenticacao, integridade e manifestacao de vontade.', 'seguranca_evidencias', 'tecnologia', 'Reconhece o metodo de assinatura e o arranjo probatorio aplicavel.', true),
('e7265639-c0e5-54cb-9492-2b9f83df84dc', 'Autenticacao do signatario', 'O processo de assinatura podera exigir autenticacao por {{metodosAutenticacao}}, de forma proporcional ao risco do contrato, ao perfil das partes e a criticidade da operacao.', 'seguranca_evidencias', 'tecnologia', 'Eleva o nivel probatorio conforme risco e valor da operacao.', true),
('18f0fd68-839b-5f23-aee0-4e38a53e061a', 'Pacote de evidencias exportavel', 'Sempre que tecnicamente disponivel, a plataforma manterá pacote de evidencias exportavel contendo historico do documento, registros de assinatura, metadados de autenticacao, hashes, IP, user agent, carimbos temporais e referencias de versao do conteudo apresentado ao signatario.', 'seguranca_evidencias', 'tecnologia', 'Define conteudo minimo do evidence pack.', true),
('f6cb147b-7b12-50dc-938a-45c0d01a73da', 'Limitacao de responsabilidade em B2B', 'Em relacoes empresariais, a responsabilidade total da contratada por perdas e danos decorrentes deste contrato limita-se a {{limiteResponsabilidade}}, ressalvados os casos excluidos por carve-out especifico.', 'responsabilidade_garantias', 'tecnologia', 'Cap de responsabilidade tipico para contratos empresariais equilibrados.', true),
('6a3c5610-f3f6-56f6-a408-e79ef1f09583', 'Exclusao de danos indiretos', 'Salvo dolo, fraude ou hipoteses legalmente irrenunciaveis, a contratada nao respondera por danos indiretos, lucros cessantes, perda de oportunidade, dano reputacional ou interrupcao de negocios do contratante.', 'responsabilidade_garantias', 'tecnologia', 'Reduz exposicao a lucros cessantes e danos reflexos quando juridicamente admitido.', true),
('21c1120d-a3ef-524d-afa3-51e57d90b16f', 'Carve-outs da limitacao', 'As limitacoes de responsabilidade previstas neste contrato nao se aplicam a {{excecoesResponsabilidade}}, nem as demais hipoteses em que a lei vede exclusao ou restricao de responsabilidade.', 'responsabilidade_garantias', NULL, 'Mantem equilibrio juridico ao excluir hipoteses graves do cap.', true),
('0f9eadf7-5de0-5469-8c21-d3db957731af', 'Indenizacao por violacao de propriedade intelectual', 'Em alegacoes de violacao de propriedade intelectual decorrentes do uso regular do objeto contratado, as partes cooperarao conforme {{regraDefesaIP}}, excluidas hipoteses causadas por conteudo, instrucoes ou materiais fornecidos pelo contratante.', 'responsabilidade_garantias', 'tecnologia', 'Disciplina defesa e mitigacao em alegacoes de infracao a direitos de terceiros.', true),
('501df22c-9db3-5b9b-98a0-08d6f06f7f6d', 'Garantias e declaracoes', 'A contratada declara que executara os servicos com diligencia compativel com {{padraoPrestacao}}. Salvo previsao expressa, nao ha garantia de resultado economico, lucro, aprovacao regulatoria ou desempenho comercial especifico.', 'responsabilidade_garantias', NULL, 'Organiza promessas minimas sem gerar garantia absoluta de resultado.', true),
('c5e77369-b3df-5774-9bb4-18a65232b654', 'SLA e disponibilidade', 'Nos servicos em nuvem, a contratada envidara esforcos para manter disponibilidade mensal de {{slaDisponibilidade}}, excluidos eventos de manutencao programada, forca maior e falhas de terceiros fora do seu controle razoavel.', 'responsabilidade_garantias', 'saas', 'Define compromisso objetivo de disponibilidade para SaaS.', true),
('53ff28b9-76aa-5867-8420-0793a9199830', 'Forca maior', 'Nenhuma parte respondera por atraso ou inadimplemento causado por evento de forca maior ou caso fortuito, desde que comunique a ocorrencia e adote medidas razoaveis para mitigar os efeitos do evento.', 'responsabilidade_garantias', NULL, 'Afasta responsabilizacao por eventos externos inevitaveis.', true),
('3bb3945d-0885-5b19-bab1-a88ee9b3fbf0', 'Uso adequado da plataforma', 'O contratante devera utilizar a plataforma conforme a lei, este contrato e a documentacao de uso, sendo responsavel por credenciais, atos de usuarios autorizados e conteudos inseridos sob sua conta, salvo falha comprovada de seguranca imputavel a contratada.', 'responsabilidade_garantias', 'saas', 'Distribui responsabilidades sobre uso indevido, credenciais e conteudo do cliente.', true),
('89374ac1-8ccb-56ff-8efc-52ecc468dfd2', 'Clausula penal calibrada', 'Quando aplicavel, a clausula penal sera fixada em {{multaRescisoriaPercentual}}% sobre a base contratual pertinente, observada proporcionalidade com o inadimplemento e possibilidade de reducao equitativa nos termos da lei.', 'responsabilidade_garantias', NULL, 'Evita multa desconectada da funcao do contrato e do inadimplemento.', true),
('094371cd-6319-5a51-a4c6-67836e9ca70f', 'Rescisao imotivada', 'Qualquer parte podera rescindir o contrato sem motivacao especifica mediante aviso previo escrito de {{avisoPrevioDias}} dias, permanecendo devidos os valores ja vencidos e os servicos efetivamente prestados ate a data de termino.', 'rescisao_continuidade', NULL, 'Organiza saida ordinaria do contrato sem litigio desnecessario.', true),
('baa50fa6-b6d4-5c71-9c21-57969b308d90', 'Rescisao por inadimplemento', 'O descumprimento contratual relevante autoriza a parte adimplente a notificar a parte infratora para sanar a irregularidade em ate {{prazoCuraDias}} dias, sob pena de rescisao motivada, sem prejuizo das medidas de cobranca e indenizacao cabiveis.', 'rescisao_continuidade', NULL, 'Preve prazo de cura e gatilho para resolucao contratual.', true),
('930a2b4e-8644-52fc-bbe1-4c780a2aff03', 'Multa por rescisao antecipada', 'A rescisao antecipada sem causa, quando aplicavel ao modelo economico do contrato, sujeita a parte resiliente a multa de {{multaRescisoriaPercentual}}% sobre a parcela remanescente pertinente, sem prejuizo do pagamento do que ja tiver sido executado.', 'rescisao_continuidade', NULL, 'Compensa custos de mobilizacao e quebra abrupta do ciclo do contrato.', true),
('9f760125-8a65-5fcb-a6d7-a37899306610', 'Pagamento proporcional ao executado', 'Na hipotese de encerramento antecipado, permanecem exigiveis os valores proporcionais ao trabalho ja executado, as licencas ja utilizadas e as despesas validamente assumidas para atendimento do contrato.', 'rescisao_continuidade', NULL, 'Evita enriquecimento sem causa no encerramento do projeto.', true),
('2324fa63-f289-5509-a084-8d8df08008da', 'Transicao e handover', 'Quando contratado ou necessario a continuidade operacional, a contratada prestara handover conforme {{regraHandover}}, mediante escopo, prazo e preco compativeis com o esforco adicional.', 'rescisao_continuidade', 'saas', 'Ajuda a desmobilizar o contrato sem ruptura operacional abrupta.', true),
('37dc8cb1-e98b-5a3e-bbff-b2f6673b06e7', 'Continuidade e acesso a dados', 'Encerrado o contrato, a contratada preservara os dados e documentos do contratante pelo prazo operacional de {{janelaExportacaoDias}} dias para fins de exportacao, regularizacao financeira e auditoria, apos o qual podera proceder ao descarte seguro conforme sua politica de retencao.', 'rescisao_continuidade', 'saas', 'Garante janela minima de retirada de dados e documentos.', true),
('9aba66c7-843d-5f9e-838b-e1e6d3c3803c', 'Sobrevivencia de obrigacoes', 'Permanecerao em vigor apos o termino do contrato as obrigacoes de confidencialidade, propriedade intelectual, auditoria de evidencias, pagamentos pendentes, responsabilidade por atos preteritos e protecao de dados na extensao legal e contratualmente cabivel.', 'rescisao_continuidade', NULL, 'Mantem vigentes obrigacoes que naturalmente sobrevivem ao termino.', true),
('b76df63b-27c1-5997-b9df-153aaf5c6231', 'Eleicao de foro com pertinencia', 'Para relacoes empresariais, fica eleito o foro de {{foroCidadeUF}}, por guardar pertinencia com {{foroPertinencia}}, sem prejuizo de medidas urgentes em foro competente por lei.', 'disputas_comunicacoes', NULL, 'Adequa a clausula de foro a redacao introduzida pela Lei 14.879/2024.', true),
('5c428e0a-3a12-5d3f-abb4-bf99cd7f537a', 'Foro favoravel ao consumidor', 'Em relacoes de consumo, prevalecera o foro legalmente mais favoravel ao consumidor, sendo invalida interpretacao que imponha deslocamento abusivo ou dificulte o acesso ao Judiciario.', 'disputas_comunicacoes', NULL, 'Evita clausula potencialmente abusiva em relacoes de consumo.', true),
('bba51d87-d259-528b-bdf5-4d1949886e01', 'Mediacao e arbitragem opcional', 'Antes do ajuizamento de acao judicial, as partes buscarao solucao negociada e, se assim optarem no caso concreto, poderao submeter o litigio a mediacao ou arbitragem administrada por {{camaraArbitral}}.', 'disputas_comunicacoes', NULL, 'Cria escada privada de resolucao para contratos empresariais.', true),
('5167b715-487d-5b24-9fc8-c6f2d636b712', 'Comunicacoes eletronicas', 'As notificacoes e comunicacoes contratuais poderao ser realizadas por e-mail para {{emailFormal}}, cabendo a cada parte manter seus dados atualizados. Registros tecnicos de envio, entrega e autenticacao poderao ser utilizados como prova do fluxo de comunicacao.', 'disputas_comunicacoes', NULL, 'Formaliza e-mail como canal contratual com suporte probatorio.', true),
('3b3b4c2c-4d77-55b5-8d3f-73a81a4d8122', 'Alteracoes contratuais', 'Qualquer aditivo, waiver ou alteracao relevante deste contrato exigira registro escrito em meio idoneo e aceite das partes por mecanismo contratualmente valido, nao se presumindo modificacao estrutural por mera tolerancia operacional.', 'disputas_comunicacoes', NULL, 'Evita alegacao de aditivo verbal implicito e sem lastro.', true),
('6405f5f7-cf96-51a9-b23e-b844133b033b', 'Prova em caso de impugnacao da assinatura', 'Se houver impugnacao fundamentada da contratacao eletronica, a parte que apresentar o contrato devera disponibilizar, na extensao tecnicamente disponivel e juridicamente adequada, os registros de autenticacao, trilha de auditoria, versao assinada e evidencias de integridade do documento.', 'disputas_comunicacoes', NULL, 'Alinha o contrato ao valor probatorio esperado em litigios de assinatura contestada.', true),
('9d2e7432-3219-53de-9e50-03d769971988', 'Anticorrupcao', 'As partes declaram que cumprirao a legislacao anticorrupcao aplicavel e nao praticarao ato que possa gerar vantagem indevida, fraude a licitacao, conflito improprio com agente publico ou ocultacao de pagamentos ilicitos.', 'compliance_operacional', NULL, 'Clausula empresarial padrao para contratos corporativos.', true),
('d5a75553-5c4f-5ad1-9643-4594b6ac910c', 'Auditoria de compliance e evidencias', 'Quando houver exigencia regulatoria, contratual ou de risco elevado, as partes poderao verificar conformidade documental e operacional conforme {{regraAuditoria}}, preservados sigilo, protecao de dados e limites razoaveis de frequencia e escopo.', 'compliance_operacional', 'tecnologia', 'Permite revisao proporcional de trilhas de prova e politicas aplicaveis.', true),
('3cf6a94a-ca24-521a-ba80-32dd43ef0c74', 'Vedacao a clausulas desconexas do contexto', 'O contrato sera interpretado de modo contextual e coerente com a operacao descrita, devendo ser evitada a inclusao de clausulas tecnicamente desconexas ou nao operacionalizaveis no fluxo real da contratacao.', 'compliance_operacional', NULL, 'Evita poluicao contratual e reforca coerencia entre texto e operacao.', true)
